const raw = String($json.text || '').replace(/\r\n/g, '\n').trim();

function stripPostArtifacts(input) {
  let text = String(input || '').replace(/\r\n/g, '\n').trim();
  const markers = [
    'Image Generation Prompt:',
    'Image Prompt:',
    'Video Prompt:',
    'Prompt:',
    '🖼️ **IMG PROMPT:**',
    '🖼️ **Image Prompt:**',
    '🎬 **VIDEO PROMPT:**',
  ];
  for (const marker of markers) {
    const idx = text.toLowerCase().indexOf(marker.toLowerCase());
    if (idx >= 0) {
      text = text.slice(0, idx).trim();
    }
  }
  const socialMatch = text.match(/(?:^|\n)\s*(?:\*\*)?Social Media Post(?:\*\*)?:\s*([\s\S]*?)(?:\n\s*(?:\*\*)?(?:Image Generation Prompt|Video Prompt)(?:\*\*)?:|$)/i);
  if (socialMatch) {
    text = socialMatch[1].trim();
  }
  text = text.replace(/^---+\s*$/gm, '').replace(/^\s*(?:\*\*)?Social Media Post(?:\*\*)?:\s*/i, '').replace(/\n{3,}/g, '\n\n').trim();
  return text;
}

const text = stripPostArtifacts(raw);
return [{ json: { ...$json, text } }];

