const integrations = $input.all().map((item) => item.json).filter((item) => !item.disabled);
const sourceUpload = $node['Upload Source Media'].json || {};
const draft = $node['Extract Draft'].json;
const publicUploadBase = 'http://192.168.1.59:4007';

function toPublicUploadUrl(input) {
  const value = String(input || '').trim();
  if (!value) return value;
  return value
    .replace(/^https?:\/\/localhost:4007/i, publicUploadBase)
    .replace(/^https?:\/\/127\.0\.0\.1:4007/i, publicUploadBase);
}

function stripPostArtifacts(input) {
  let text = String(input || '').split('\r\n').join('\n').trim();
  const markers = [
    'Image Generation Prompt:',
    'Image Prompt:',
    'Prompt:',
    '🖼️ **IMG PROMPT:**',
    '🖼️ **Image Prompt:**',
  ];
  for (const marker of markers) {
    const idx = text.toLowerCase().indexOf(marker.toLowerCase());
    if (idx >= 0) {
      text = text.slice(0, idx).trim();
    }
  }

  const lines = text.split('\n').map((line) => line.trimRight());
  const filtered = [];
  let sawSocialLabel = false;
  for (const line of lines) {
    const normalized = line.trim().toLowerCase();
    if (normalized === '---') continue;
    if (normalized === 'social media post:' || normalized === '**social media post:**' || normalized === 'social media post' || normalized === '**social media post**:') {
      sawSocialLabel = true;
      continue;
    }
    if (normalized === 'image generation prompt:' || normalized === '**image generation prompt:**' || normalized === 'image prompt:' || normalized === '**image prompt:**' || normalized === 'prompt:' || normalized === '**img prompt:**') {
      break;
    }
    filtered.push(line);
  }

  text = filtered.join('\n').trim();
  if (!text && sawSocialLabel) {
    text = String(input || '').split('\r\n').join('\n').trim();
  }
  while (text.includes('\n\n\n')) text = text.split('\n\n\n').join('\n\n');
  return text.trim();
}

function cleanPostText(input) {
  return stripPostArtifacts(input);
}

function titleCase(input) {
  return String(input || '')
    .replace(/[-_]+/g, ' ')
    .replace(/\b\w/g, (m) => m.toUpperCase())
    .replace(/\s+/g, ' ')
    .trim();
}

function buildYoutubeTitle(sourceTitle, text, sourceHandle) {
  const rawText = String(text || '');
  const firstSentence = rawText
    .split(/(?<=[.!?])\s+/)[0]
    .replace(/\s+/g, ' ')
    .trim();
  const strippedFirst = firstSentence
    .replace(/\s*#\w+/g, '')
    .replace(/\s*Source:\s*@?[\w.]+/ig, '')
    .trim();
  const handle = String(sourceHandle || '').replace(/^@/, '').trim();
  const handleTitle = titleCase(handle || sourceTitle).replace(/\bPopular\b/ig, '').replace(/\s+/g, ' ').trim();
  const candidate = strippedFirst || handleTitle || 'Sarah Nutri Short';
  const prefix = 'Sarah Nutri: ';
  const finalTitle = candidate.toLowerCase().startsWith('sarah nutri') ? candidate : prefix + candidate;
  return finalTitle.replace(/\s+/g, ' ').trim();
}

function isVideoPath(input) {
  const value = String(input || '').toLowerCase();
  if (!value) return false;
  return value.includes('.mp4') || value.includes('.mov') || value.includes('.webm') || value.includes('.mkv');
}

const generatedMediaPath = toPublicUploadUrl(draft.generatedMediaPath || draft.generatedMediaUrl || '');
const uploadedSourcePath = toPublicUploadUrl(sourceUpload.path || '');
const directSourcePath = toPublicUploadUrl(draft.sourceVideoUrl || draft.sourceImageUrl || '');
const sourceMediaPath = directSourcePath || uploadedSourcePath;
const sourceMedia = [];
if (sourceMediaPath) {
  sourceMedia.push({
    id: sourceUpload.id || (draft.sourceVideoUrl ? 'source-video' : 'source-image'),
    path: sourceMediaPath,
  });
}
const generatedMedia = generatedMediaPath ? [{ id: draft.generatedMediaId || 'generated-video', path: generatedMediaPath }] : [];
const mediaChoice = (draft.mediaChoice || 'source').toLowerCase();
const preferGenerated = !draft.sourceVideoUrl && generatedMedia.length > 0;
const useGenerated = (mediaChoice === 'generated' && generatedMedia.length > 0) || preferGenerated;
const media = useGenerated ? generatedMedia : sourceMedia.length ? sourceMedia : generatedMedia;
const mediaSource = useGenerated ? 'generated' : sourceMedia.length ? 'source' : generatedMedia.length ? 'generated' : 'none';
const hasVideoMedia = media.some((item) => isVideoPath(item.path)) || isVideoPath(draft.sourceVideoUrl) || isVideoPath(draft.generatedMediaUrl) || isVideoPath(draft.generatedMediaPath);
const sourceHandle = String(draft.sourceHandle || '').trim();
const sourceCredit = sourceHandle ? (sourceHandle.startsWith('@') ? sourceHandle : '@' + sourceHandle) : '';
let postText = cleanPostText(draft.postText || '');
if (sourceCredit && !postText.toLowerCase().includes(sourceCredit.toLowerCase())) {
  postText = postText ? postText + '\n\nSource: ' + sourceCredit : 'Source: ' + sourceCredit;
}
const posts = [];
const postedTo = [];
const skipped = [];

for (const integration of integrations) {
  const identifier = integration.identifier;

  if (identifier === 'facebook') {
    if (!media.length) {
      skipped.push({ integration: identifier, reason: 'No image or video media available' });
      continue;
    }
    posts.push({
      integration: { id: integration.id },
      value: [{ content: postText, image: media }],
      settings: {
        __type: 'facebook',
        url: draft.sourceLink || '',
      },
    });
    postedTo.push(identifier);
    continue;
  }

  if (identifier === 'instagram' || identifier === 'instagram-standalone') {
    if (!media.length) {
      skipped.push({ integration: identifier, reason: 'No image or video media available' });
      continue;
    }
    posts.push({
      integration: { id: integration.id },
      value: [{ content: postText, image: media }],
      settings: {
        __type: identifier,
        post_type: 'post',
        collaborators: [],
      },
    });
    postedTo.push(identifier);
    continue;
  }

  if (identifier === 'youtube') {
    if (!draft.sourceVideoUrl) {
      skipped.push({ integration: identifier, reason: 'No video source available yet' });
      continue;
    }
    posts.push({
      integration: { id: integration.id },
      value: [{ content: postText, image: media }],
      settings: {
        __type: 'youtube',
        title: buildYoutubeTitle(draft.sourceTitle, postText, sourceHandle).substring(0, 95),
        type: 'public',
        tags: [],
      },
    });
    postedTo.push(identifier);
    continue;
  }

  if (identifier === 'pinterest') {
    skipped.push({ integration: identifier, reason: 'Pinterest production publishing is blocked by Trial app access' });
    continue;
  }

  skipped.push({ integration: identifier, reason: 'No workflow posting template configured yet' });
}

if (!posts.length) {
  throw new Error('No eligible Postiz integrations are configured for automatic posting');
}

const body = {
  type: 'now',
  shortLink: false,
  date: new Date().toISOString(),
  tags: [],
  posts,
};

return [{ json: { postizBody: JSON.stringify(body), postedTo, skipped, mediaSource, mediaChoice, sourceHandle: sourceCredit, hasVideoMedia } }];

const routing = $node['Build Postiz Body'].json;
const response = $input.first().json;
const postedTo = routing.postedTo || [];
const skipped = routing.skipped || [];
const mediaSource = routing.mediaSource || 'none';
const mediaChoice = routing.mediaChoice || 'source';
const postedLine = postedTo.length ? 'Sent to Postiz draft queue for: ' + postedTo.join(', ') + '.' : 'No eligible integrations were posted.';
const skippedLine = skipped.length ? ' Skipped: ' + skipped.map((item) => item.integration + ' (' + item.reason + ')').join(', ') + '.' : '';
const choiceLine = ' Selection: ' + mediaChoice + '.';
const mediaLine = mediaSource === 'generated' ? ' Used generated media.' : mediaSource === 'source' ? ' Used source media.' : ' No media asset was attached.';
return [{ json: { ok: true, action: 'approve', message: postedLine + skippedLine + choiceLine + mediaLine, postedTo, skipped, mediaSource, mediaChoice, postizResponse: response } }];
